import{_ as e,o as s,c as l,ag as i}from"./chunks/framework.eQLvDOR_.js";const k=JSON.parse('{"title":"Claude Code Skills 完全活用ガイド 2026 — 個人最適化からチーム展開まで","description":"","frontmatter":{"title":"Claude Code Skills 完全活用ガイド 2026 — 個人最適化からチーム展開まで","source":"https://qiita.com/nogataka/items/ad9995fb1b3db7055740","category":"[Claude_Code_Skills]","clipped_at":"2026-04-04","tags":["claude-code-skills"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/Claude_Code_Skills/Claude_Code_Skills - Claude-Code-Skills-完全活用ガイド-2026-—-個人最適化から团队展开まで.md","filePath":"library/Claude_Code_Skills/Claude_Code_Skills - Claude-Code-Skills-完全活用ガイド-2026-—-個人最適化から团队展开まで.md","lastUpdated":null}'),t={name:"library/Claude_Code_Skills/Claude_Code_Skills - Claude-Code-Skills-完全活用ガイド-2026-—-個人最適化から团队展开まで.md"};function n(r,a,d,p,o,h){return s(),l("div",null,[...a[0]||(a[0]=[i(`<p><a href="https://qiita.com/nogataka" target="_blank" rel="noreferrer">@nogataka</a></p><p>127</p><p>投稿日</p><h2 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h2><p>2026年3月現在、Claude Code Skillsに関するはてなブックマークが爆発的に伸びている。 <a href="https://dev.classmethod.jp/articles/claude-code-skills-for-cloud-bu-consulting-members/" target="_blank" rel="noreferrer">クラスメソッドの入門記事が783users</a> 、 <a href="https://atmarkit.itmedia.co.jp/ait/articles/2603/10/news010.html" target="_blank" rel="noreferrer">Anthropic公式講座の解説が763users</a> 、 <a href="https://dev.henry.jp/entry/claude-code-skills-for-teams" target="_blank" rel="noreferrer">チーム展開の課題に関する記事が74users</a> ——Skillsは今週最も注目された開発トピックである。</p><p>本記事では、公式ドキュメントや公開されている実践記事に加え、筆者自身の運用経験をもとに「Skills設計パターン集」としてまとめる。入門レベルの紹介は既に良い記事が揃っているため、本記事では設計と運用にフォーカスする。</p><h2 id="skillsの基本概念" tabindex="-1">Skillsの基本概念 <a class="header-anchor" href="#skillsの基本概念" aria-label="Permalink to &quot;Skillsの基本概念&quot;">​</a></h2><h3 id="skillsとは何か" tabindex="-1">Skillsとは何か <a class="header-anchor" href="#skillsとは何か" aria-label="Permalink to &quot;Skillsとは何か&quot;">​</a></h3><p>Skillsは、Claude Codeに「特定の仕事の進め方」を教えるための仕組みである。ポータブルな専門知識のバンドルと考えるとわかりやすい。</p><p>構造はシンプルで、フォルダ1つに必要なファイルをまとめるだけである。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-skill/</span></span>
<span class="line"><span>├── SKILL.md          # 必須: 指示とメタデータ</span></span>
<span class="line"><span>├── scripts/          # 任意: 自動化スクリプト</span></span>
<span class="line"><span>├── references/       # 任意: 参考資料</span></span>
<span class="line"><span>└── assets/           # 任意: テンプレート等</span></span></code></pre></div><h3 id="progressive-disclosure-—-コンテキスト効率の要" tabindex="-1">Progressive Disclosure — コンテキスト効率の要 <a class="header-anchor" href="#progressive-disclosure-—-コンテキスト効率の要" aria-label="Permalink to &quot;Progressive Disclosure — コンテキスト効率の要&quot;">​</a></h3><p>Skillsの設計で最も重要な概念が**Progressive Disclosure（段階的開示）**である。</p><p>Claude Codeは以下の順序でSkillの情報を読み込む。</p><ol><li>Skill名と <code>description</code> だけを確認する（トリガー判定）</li><li>関連するSKILL.mdの本文をロードする（実行指示）</li><li>必要なときだけ <code>references/</code> 内のファイルにアクセスする（補足情報）</li></ol><p>この設計により、コンテキストウィンドウを無駄に消費しない。20個のSkillがインストールされていても、実際にロードされるのは1〜2個だけで済む。</p><h3 id="claude-mdとの使い分け" tabindex="-1">CLAUDE.mdとの使い分け <a class="header-anchor" href="#claude-mdとの使い分け" aria-label="Permalink to &quot;CLAUDE.mdとの使い分け&quot;">​</a></h3><table tabindex="0"><thead><tr><th>観点</th><th>Skills</th><th>CLAUDE.md</th></tr></thead><tbody><tr><td>目的</td><td>特定タスクの実行手順</td><td>プロジェクト全体の文脈・規約</td></tr><tr><td>スコープ</td><td>必要なときだけロード</td><td>常にロードされる</td></tr><tr><td>可搬性</td><td>プロジェクト横断で再利用可能</td><td>リポジトリ固有</td></tr><tr><td>適した内容</td><td>ワークフロー、テンプレート、自動化</td><td>コーディング規約、環境設定、チーム方針</td></tr></tbody></table><p>判断基準は単純で、「常に適用すべきルール」はCLAUDE.md、「特定の作業のときだけ必要な手順」はSkillsに書く。</p><h2 id="skills設計パターン集" tabindex="-1">Skills設計パターン集 <a class="header-anchor" href="#skills設計パターン集" aria-label="Permalink to &quot;Skills設計パターン集&quot;">​</a></h2><p>実務で効果の高かったパターンを紹介する。</p><h3 id="パターン1-ワークフロー自動化型" tabindex="-1">パターン1: ワークフロー自動化型 <a class="header-anchor" href="#パターン1-ワークフロー自動化型" aria-label="Permalink to &quot;パターン1: ワークフロー自動化型&quot;">​</a></h3><p>定型作業の手順をSkillにまとめるパターン。最も基本的で、効果も実感しやすい。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">write-draft</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">記事の下書きを生成する必要があるとき。「記事を書いて」「下書きして」で発火</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p><code>description</code> の書き方がトリガー精度を決める。「プロフェッショナルなドキュメントを作成する」のような曖昧な記述ではなく、「記事の下書きを生成する必要があるとき」のように具体的な状況を書く。</p><h3 id="パターン2-テンプレート駆動型" tabindex="-1">パターン2: テンプレート駆動型 <a class="header-anchor" href="#パターン2-テンプレート駆動型" aria-label="Permalink to &quot;パターン2: テンプレート駆動型&quot;">​</a></h3><p>テンプレートを <code>references/</code> に格納し、SKILL.mdでその使い方を指示するパターン。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>proposal-creation-toolkit/</span></span>
<span class="line"><span>├── SKILL.md</span></span>
<span class="line"><span>└── templates/</span></span>
<span class="line"><span>    ├── how-to/template.md</span></span>
<span class="line"><span>    ├── concept/template.md</span></span>
<span class="line"><span>    └── troubleshooting/template.md</span></span></code></pre></div><p>SKILL.mdには「どのテンプレートをいつ使うか」の判断基準を書く。テンプレート自体は <code>templates/</code> に分離することで、SKILL.mdを短く保てる。</p><h3 id="パターン3-パイプライン型" tabindex="-1">パターン3: パイプライン型 <a class="header-anchor" href="#パターン3-パイプライン型" aria-label="Permalink to &quot;パターン3: パイプライン型&quot;">​</a></h3><p>複数のステップを順番に実行するパターン。リサーチ→分析→出力のような流れに向いている。</p><p>ポイントは、各ステップの完了条件を明確にすることである。「調査する」ではなく「3つ以上のソースから情報を取得し、比較表を作成する」のように書く。途中成果をファイルに保存する指示も入れておくと、長時間タスクで途中結果が失われない。</p><h3 id="パターン4-サブエージェント分離型" tabindex="-1">パターン4: サブエージェント分離型 <a class="header-anchor" href="#パターン4-サブエージェント分離型" aria-label="Permalink to &quot;パターン4: サブエージェント分離型&quot;">​</a></h3><p><code>context: fork</code> を指定して、メインのコンテキストウィンドウとは別の空間で実行するパターン。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">deep-research</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">深い調査が必要なとき。「調べて」「リサーチして」で発火</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">context</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">fork</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>調査やレビューなど、大量の情報を読み込む必要があるが、その詳細をメインの会話に持ち込みたくない場合に有効である。結果の要約だけがメインコンテキストに返される。</p><h3 id="パターン5-マルチエージェント協調型" tabindex="-1">パターン5: マルチエージェント協調型 <a class="header-anchor" href="#パターン5-マルチエージェント協調型" aria-label="Permalink to &quot;パターン5: マルチエージェント協調型&quot;">​</a></h3><p>複数のサブエージェントを並行起動し、それぞれに異なる役割を持たせるパターン。記事執筆であれば、リサーチ担当・構成担当・レビュー担当を分ける、といった使い方ができる。</p><p>注意点として、エージェント間の依存関係を明確にする必要がある。「リサーチが終わってから構成を考える」なのか「並行して進めて後で統合する」のかで、SKILL.mdの書き方が変わる。</p><h3 id="パターン6-ガードレール型" tabindex="-1">パターン6: ガードレール型 <a class="header-anchor" href="#パターン6-ガードレール型" aria-label="Permalink to &quot;パターン6: ガードレール型&quot;">​</a></h3><p>特定の操作を行う前に、チェックリストや検証を実行するパターン。PRレビュー、デプロイ前チェック、セキュリティスキャンなどに向いている。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pr-review</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">PRレビューを実行するとき。コード変更後に自動的に発火</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>「コードを変更したあとに自動的にレビューする」という使い方は、CI/CDパイプラインのローカル版として機能する。</p><h2 id="チーム展開の3つの課題と解決策" tabindex="-1">チーム展開の3つの課題と解決策 <a class="header-anchor" href="#チーム展開の3つの課題と解決策" aria-label="Permalink to &quot;チーム展開の3つの課題と解決策&quot;">​</a></h2><p>個人で使う分にはSkillsは自由に設計できる。しかし、チームで共有しようとした瞬間に固有の課題が発生する。 <a href="https://dev.henry.jp/entry/claude-code-skills-for-teams" target="_blank" rel="noreferrer">Henryのエンジニアブログ</a> で報告された課題と、それに対する解決策を整理する。</p><h3 id="課題1-変更の評価が難しい" tabindex="-1">課題1: 変更の評価が難しい <a class="header-anchor" href="#課題1-変更の評価が難しい" aria-label="Permalink to &quot;課題1: 変更の評価が難しい&quot;">​</a></h3><p>Skillの設計パターンが未確立のため、PRレビューが主観的な判断に依存する。「このdescriptionは適切か」「このステップ数は妥当か」という問いに対して、客観的な基準がない。</p><p><strong>解決策</strong>: Skillに対するテストケースを定義する。「このSkillに○○という入力を与えたとき、期待される出力は△△」という形式で検証可能にする。完全な自動テストは難しいが、チェックリストレベルでも効果がある。</p><h3 id="課題2-利用者間のニーズ相違" tabindex="-1">課題2: 利用者間のニーズ相違 <a class="header-anchor" href="#課題2-利用者間のニーズ相違" aria-label="Permalink to &quot;課題2: 利用者間のニーズ相違&quot;">​</a></h3><p>同じSkillに対して、メンバーAは「もっと詳細な指示がほしい」、メンバーBは「シンプルにしてほしい」と要求する。経験レベルや作業スタイルの違いが表面化する。</p><p><strong>解決策</strong>: チームSkillを「必須ツール」ではなく「スターターキット」として位置づける。チームSkillをフォークして個人的にカスタマイズすることを推奨し、改善があればチームにフィードバックする。「個人で試す→検証する→チームに共有する」というサイクルを回す。</p><h3 id="課題3-ポータビリティの喪失" tabindex="-1">課題3: ポータビリティの喪失 <a class="header-anchor" href="#課題3-ポータビリティの喪失" aria-label="Permalink to &quot;課題3: ポータビリティの喪失&quot;">​</a></h3><p>チーム管理のSkillに依存すると、異動・転職時に再利用可能な資産を持ち出せない。特に、会社固有のAPI仕様やビジネスロジックがSkillに混入していると、分離が困難になる。</p><p><strong>解決策</strong>: 個人SkillとチームSkillを別リポジトリで管理する。個人Skillには汎用的なプロンプトパターンと思考フレームワークのみを含め、会社固有情報はチームSkillに閉じ込める。</p><h2 id="skills設計のアンチパターン" tabindex="-1">Skills設計のアンチパターン <a class="header-anchor" href="#skills設計のアンチパターン" aria-label="Permalink to &quot;Skills設計のアンチパターン&quot;">​</a></h2><h3 id="_1-skill-mdの肥大化" tabindex="-1">1. SKILL.mdの肥大化 <a class="header-anchor" href="#_1-skill-mdの肥大化" aria-label="Permalink to &quot;1\\. SKILL.mdの肥大化&quot;">​</a></h3><p>SKILL.mdに500行以上の指示を詰め込むパターン。コンテキストウィンドウを圧迫し、他のSkillとの同時利用が困難になる。</p><p>SKILL.mdは「いつ・何を・どの順序で」の骨格だけにとどめ、詳細な参考資料は <code>references/</code> に分離する。</p><h3 id="_2-descriptionの曖昧さ" tabindex="-1">2. descriptionの曖昧さ <a class="header-anchor" href="#_2-descriptionの曖昧さ" aria-label="Permalink to &quot;2\\. descriptionの曖昧さ&quot;">​</a></h3><p>「便利なユーティリティ」「開発を効率化する」のような抽象的なdescriptionは、自動トリガーの精度を著しく低下させる。</p><p>「TypeScriptのユニットテストを作成する必要があるとき」のように、具体的な状況と対象を明記する。</p><h3 id="_3-手動呼び出しへの依存" tabindex="-1">3. 手動呼び出しへの依存 <a class="header-anchor" href="#_3-手動呼び出しへの依存" aria-label="Permalink to &quot;3\\. 手動呼び出しへの依存&quot;">​</a></h3><p><code>/skill-name</code> での手動起動ばかりになっている状態は、descriptionの改善が必要なサインである。適切なdescriptionが設定されていれば、自然な会話の中でSkillが自動的に発火する。</p><h3 id="_4-状態管理の欠如" tabindex="-1">4. 状態管理の欠如 <a class="header-anchor" href="#_4-状態管理の欠如" aria-label="Permalink to &quot;4\\. 状態管理の欠如&quot;">​</a></h3><p>長時間タスクで途中成果をファイルに保存しないパターン。コンテキストウィンドウがいっぱいになったり、セッションが切れたりしたときにすべてが失われる。</p><p>重要な中間成果は必ずファイルに保存する指示をSKILL.mdに含める。</p><h3 id="_5-権限の野放し" tabindex="-1">5. 権限の野放し <a class="header-anchor" href="#_5-権限の野放し" aria-label="Permalink to &quot;5\\. 権限の野放し&quot;">​</a></h3><p>Skillが任意のBashコマンドを実行できる状態のまま運用するパターン。 <code>allowed-tools</code> でSkillが使えるツールを制限し、意図しない操作を防ぐ。</p><h2 id="セキュリティ考慮事項" tabindex="-1">セキュリティ考慮事項 <a class="header-anchor" href="#セキュリティ考慮事項" aria-label="Permalink to &quot;セキュリティ考慮事項&quot;">​</a></h2><p>Skillsはプレーンテキストのファイルであり、任意の指示を含められる。これは柔軟性の源泉であると同時に、セキュリティリスクでもある。</p><h3 id="第三者skillのリスク" tabindex="-1">第三者Skillのリスク <a class="header-anchor" href="#第三者skillのリスク" aria-label="Permalink to &quot;第三者Skillのリスク&quot;">​</a></h3><p>GitHubやnpmで公開されているSkillをそのままインストールすることは、見知らぬ人のシェルスクリプトを <code>sudo</code> で実行するのと本質的に変わらない。</p><p><strong>必ず確認すべき項目</strong>:</p><ul><li>SKILL.mdの内容（悪意のある指示が含まれていないか）</li><li><code>scripts/</code> 内のスクリプト（外部通信や破壊的操作がないか）</li><li><code>references/</code> 内のファイル（プロンプトインジェクションの仕込みがないか）</li></ul><h3 id="信頼できるソースの判断基準" tabindex="-1">信頼できるソースの判断基準 <a class="header-anchor" href="#信頼できるソースの判断基準" aria-label="Permalink to &quot;信頼できるソースの判断基準&quot;">​</a></h3><ul><li>自作のSkill（最も安全）</li><li>チーム内でレビュー済みのSkill</li><li>Anthropic公式リポジトリのSkill</li><li>著名なOSSプロジェクトが公開しているSkill</li></ul><p>上記以外のソースからのSkillは、全ファイルを監査してから導入する。</p><h3 id="context-forkによるリスク緩和" tabindex="-1">context: forkによるリスク緩和 <a class="header-anchor" href="#context-forkによるリスク緩和" aria-label="Permalink to &quot;context: forkによるリスク緩和&quot;">​</a></h3><p>信頼度が低いSkillを使わざるを得ない場合、 <code>context: fork</code> でサブエージェントとして隔離実行することで、メインのコンテキストへの影響を最小限に抑えられる。</p><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>Claude Code Skillsは、AIコーディングアシスタントの活用を「受動的なコード補完」から「能動的なワークフロー設計」へと引き上げる仕組みである。</p><p>設計の勘所は以下の3点に集約される。</p><ol><li><strong>descriptionが全て</strong>: 自動トリガーの精度はdescriptionの具体性で決まる</li><li><strong>Progressive Disclosureを意識する</strong>: SKILL.mdは短く、詳細は <code>references/</code> に分離</li><li><strong>個人とチームの境界を明確にする</strong>: ポータビリティを維持しつつ、チームの知識を循環させる</li></ol><p>Skillsはまだ成熟した技術ではない。設計パターンも確立途上にある。だからこそ、今の時点で自分なりのパターンを構築しておくことに価値がある。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://dev.classmethod.jp/articles/claude-code-skills-for-cloud-bu-consulting-members/" target="_blank" rel="noreferrer">Claude Code Skills (Agent Skills) 入門（クラスメソッド）</a></li><li><a href="https://atmarkit.itmedia.co.jp/ait/articles/2603/10/news010.html" target="_blank" rel="noreferrer">Anthropic公式「エージェントスキル入門」講座解説（@IT）</a></li><li><a href="https://dev.henry.jp/entry/claude-code-skills-for-teams" target="_blank" rel="noreferrer">Claude Code Skillsのチーム展開で気づいた課題と対策（Henry）</a></li></ul><p><a href="https://qiita.com/nogataka/items/ad9995fb1b3db7055740#comments" target="_blank" rel="noreferrer">2</a></p><p>コメント一覧へ移動</p><p>X（Twitter）でシェアする</p><p>Facebookでシェアする</p><p>はてなブックマークに追加する</p>`,91)])])}const u=e(t,[["render",n]]);export{k as __pageData,u as default};
